module top_module(clk, din, rst_b, dout);input din;
  input clk;
  input rst_b;
  output dout;

  reg invalid_data, r2_q;

  assign dout = r2_q & din;

  always @ (posedge clk or negedge rst_b)
    if (!rst_b)
      begin
        invalid_data <= 0;
        r2_q <= 0;
      end
    else
      begin
        invalid_data <= din;
        r2_q <= invalid_data;
      end

endmodule
